app.get('/users', (req, res) => {
  // 1. Check authentication (example: Bearer token)
  const authHeader = req.headers.authorization;
  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return res.status(401).json({ 
      error: 'Unauthorized',
      message: 'Missing or invalid authentication token'
    });
  }

  // 2. Validate query parameters (if any)
  const { limit = 10, offset = 0 } = req.query;

  // Validate and sanitize numeric inputs
  const validatedLimit = parseInt(limit, 10);
  const validatedOffset = parseInt(offset, 10);

  if (isNaN(validatedLimit) || isNaN(validatedOffset) || 
      validatedLimit < 1 || validatedLimit > 100 || 
      validatedOffset < 0) {
    return res.status(400).json({ 
      error: 'Invalid parameters',
      message: 'Limit must be 1-100, offset must be >= 0'
    });
  }

  // 3. Return sanitized data
  const users = [
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob', email: 'bob@example.com' },
  ];

  res.json({
    data: users.slice(validatedOffset, validatedOffset + validatedLimit),
    pagination: {
      limit: validatedLimit,
      offset: validatedOffset,
      total: users.length
    }
  });
});

// ============ ERROR HANDLING ============

// 404 handler
app.use((req, res) => {
  res.status(404).json({ 
    error: 'Not Found',
    message: 'The requested resource does not exist'
  });
});

// Global error handler (MUST be last)
app.use((err, req, res, next) => {
  console.error('Error:', err);

  // Don't expose stack traces in production
  const isDevelopment = process.env.NODE_ENV !== 'production';

  res.status(err.status || 500).json({
    error: err.message || 'Internal Server Error',
    message: isDevelopment ? err.stack : 'An unexpected error occurred',
    ...(isDevelopment && { stack: err.stack })
  });
});

// ============ SERVER STARTUP ============

const PORT = process.env.PORT || 3000;

// Validate port
if (isNaN(PORT) || PORT < 1 || PORT > 65535) {
  console.error('Invalid PORT. Must be between 1 and 65535');
  process.exit(1);
}

const server = app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
  console.log(`Environment: ${process.env.NODE_ENV || 'development'}`);
});

// Graceful shutdown
process.on('SIGTERM', () => {
  console.log('SIGTERM signal received: closing HTTP server');
  server.close(() => {
    console.log('HTTP server closed');
  });
});

module.exports = app;
```

